import { useState } from 'react';
import {OptionButton, SubmitButton} from "./Button"

export default function StartMenu(){
    const [quizName, setquizName] = useState("");

    return (
        <div className='container'>
            <Header quizName={quizName}></Header>
            <main className="main">
                <div className="startMenuText">
                    <h1 className='subtitle'>Welcome to the <p className='title'>Frontend Quiz!</p></h1>
                    <p className='description'>Pick a subject to get started.</p>
                </div>
                <SubmitButton name={"HTML"}> lol kek </SubmitButton>
                <OptionButton onQuizName={setquizName}>
                    <div className="content">

                    </div>
                    <div className="svgContainer">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 40 40"><path fill="#FF7E35" d="M24.508 7.607a1.25 1.25 0 0 1 .634 1.65l-10 22.5a1.25 1.25 0 1 1-2.284-1.015l10-22.5a1.251 1.251 0 0 1 1.65-.635ZM10.832 13.44a1.249 1.249 0 0 1 .1 1.765L6.674 20l4.263 4.795a1.25 1.25 0 1 1-1.87 1.66l-5-5.625a1.25 1.25 0 0 1 0-1.66l5-5.625a1.25 1.25 0 0 1 1.764-.105Zm18.337 0a1.25 1.25 0 0 1 1.765.105l5 5.625a1.25 1.25 0 0 1 0 1.66l-5 5.625a1.25 1.25 0 1 1-1.87-1.66L33.327 20l-4.262-4.795a1.25 1.25 0 0 1 .105-1.765Z"/></svg>
                    </div>
                    <p>HTML</p>
                </OptionButton>
                <OptionButton onQuizName={setquizName}>CSS</OptionButton>
                <OptionButton onQuizName={setquizName}>Javascript</OptionButton>
                <OptionButton onQuizName={setquizName}>Accessibility</OptionButton>
            </main>
        </div>
    )
}

function Header({quizName}){
    return (
        <header className="header">
            <div className="quizName">
                <h1>{quizName}</h1>
            </div>
            <ToggleColorTheme></ToggleColorTheme>
        </header>
    )
}
function ToggleColorTheme(){
    return (
        <label className="switchTheme">
            <input type="checkbox"></input>
            <span className="switch round"></span>
        </label>
    )
}
